func isReportFresh(db *sql.DB, reportType, marketplaceID, startTime, endTime string, maxAge time.Duration) bool {
	var fetched time.Time
	err := db.QueryRow(`SELECT fetched_at FROM report_cache WHERE report_type=? AND marketplace_id=? AND date_range_hash=?`,
		reportType, marketplaceID, reportRangeHash(startTime, endTime)).Scan(&fetched)
	return err == nil && time.Since(fetched) < maxAge
}

