func rowValue(row map[string]string, keys ...string) string {
	for _, key := range keys {
		normalized := normalizeReportHeader(key)
		if v := strings.TrimSpace(row[normalized]); v != "" {
			return v
		}
	}
	return ""
}

func num(row map[string]string, keys ...string) float64 {
	values := make([]string, 0, len(keys))
	for _, key := range keys {
		values = append(values, rowValue(row, key))
	}
	return amountFrom(values...)
}

func integer(row map[string]string, keys ...string) int {
	values := make([]string, 0, len(keys))
	for _, key := range keys {
		values = append(values, rowValue(row, key))
	}
	return intFrom(values...)
}

func hashRow(row map[string]string) string {
	raw, _ := json.Marshal(row)
	sum := sha256.Sum256(raw)
	return hex.EncodeToString(sum[:8])
}

func scanRows(rows *sql.Rows) ([]map[string]any, error) {
	defer rows.Close()
	cols, err := rows.Columns()
	if err != nil {
		return nil, err
	}
	var out []map[string]any
	for rows.Next() {
		vals := make([]any, len(cols))
		ptrs := make([]any, len(cols))
		for i := range vals {
			ptrs[i] = &vals[i]
		}
		if err := rows.Scan(ptrs...); err != nil {
			return nil, err
		}
		row := make(map[string]any, len(cols))
		for i, col := range cols {
			switch v := vals[i].(type) {
			case []byte:
				row[col] = string(v)
			default:
				row[col] = v
			}
		}
		out = append(out, row)
	}
	return out, rows.Err()
}
